func TestTailFollowFalseReturnsAfterSingleFetch(t *testing.T) {
	var requests atomic.Int32
	srv := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		requests.Add(1)
		if r.URL.Path != "/products" {
			t.Errorf("request path: want /products, got %s", r.URL.Path)
		}
		if got := r.Header.Get("Authorization"); got != "Bearer test-token" {
			t.Errorf("authorization header: want Bearer test-token, got %q", got)
		}
		w.Header().Set("Content-Type", "application/json")
		fmt.Fprint(w, `[{"id":"prod_1"}]`)
	}))
	defer srv.Close()

	t.Setenv("GUMROAD_BASE_URL", srv.URL)
	t.Setenv("GUMROAD_ACCESS_TOKEN", "test-token")

	var flags rootFlags
	cmd := newRootCmd(&flags)
	var stdout bytes.Buffer
	var stderr bytes.Buffer
	cmd.SetOut(&stdout)
	cmd.SetErr(&stderr)
	cmd.SetArgs([]string{"tail", "products", "--follow=false", "--interval=1ms"})

	done := make(chan error, 1)
	go func() {
		done <- cmd.Execute()
	}()

	select {
	case err := <-done:
		if err != nil {
			t.Fatalf("tail --follow=false returned error: %v", err)
		}
	case <-time.After(500 * time.Millisecond):
		t.Fatal("tail --follow=false did not return after the initial fetch")
	}

	if got := requests.Load(); got != 1 {
		t.Fatalf("tail --follow=false should fetch once, got %d requests", got)
	}
	if !strings.Contains(stdout.String(), "prod_1") {
		t.Fatalf("tail output should use command stdout, got %q", stdout.String())
	}
	if !strings.Contains(stderr.String(), "Polling products once") {
		t.Fatalf("tail diagnostics should use command stderr, got %q", stderr.String())
	}
}
